+import type { BaseIssue, BaseSchema } from '../../types/index.ts';
+import { _getStandardProps } from '../../utils/index.ts';
+import { Recur } from './recur.ts';
+import type { RecursiveSchema } from './types.ts';
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The wrapped schema.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  let resolved: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
+  const schema: RecursiveSchema<TWrapped> = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    wrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return resolved['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TWrapped>;
+  resolved = _resolveRecur(wrapped, schema);
+  return schema;
+}
+
+/**
+ * Resolves recursive placeholders in a schema graph.
+ *
+ * @param value The value to resolve.
+ * @param schema The recursive schema.
+ *
+ * @returns The resolved value.
+ *
+ * @internal
+ */
+export function _resolveRecur<TValue>(
+  value: TValue,
+  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+  values = new Map<object, object>()
+): TValue {
+  if (value === Recur) {
+    return schema as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+  const previous = values.get(value);
+  if (previous) {
+    return previous as TValue;
+  }
+  const resolved: object = Array.isArray(value)
+    ? []
+    : Object.create(Object.getPrototypeOf(value));
+  values.set(value, resolved);
+  for (const key of Reflect.ownKeys(value)) {
+    const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+    if ('value' in descriptor) {
+      descriptor.value = _resolveRecur(descriptor.value, schema, values);
+    }
+    Object.defineProperty(resolved, key, descriptor);
+  }
+  return resolved as TValue;
+}
